import React, { useEffect, useState } from "react";
import { Table, Button, Tooltip, Select } from "antd";
import { useDispatch, useSelector } from "react-redux";
import { Link } from "react-router-dom";
import { getAdminB2bOrders } from "../../features/b2b/b2bSlice";
import { getSocket } from "../../socket";
import { Search, ShoppingBag, Eye, CreditCard } from "lucide-react";

const B2bOrderList = () => {
  const dispatch = useDispatch();
  const [searchText, setSearchText] = useState("");
  const [filterStatus, setFilterStatus] = useState("all");
  const [filterType, setFilterType] = useState("all");

  useEffect(() => {
    const params = {};
    if (filterStatus !== "all") params.procurementStatus = filterStatus;
    if (filterType !== "all") params.orderType = filterType;
    if (searchText) params.search = searchText;

    dispatch(getAdminB2bOrders(params));
  }, [dispatch, searchText, filterStatus, filterType]);

  // Real-time B2B order updates
  useEffect(() => {
    const socket = getSocket();
    if (!socket) return;

    const refreshOrders = () => {
      const params = {};
      if (filterStatus !== "all") params.procurementStatus = filterStatus;
      if (filterType !== "all") params.orderType = filterType;
      if (searchText) params.search = searchText;
      dispatch(getAdminB2bOrders(params));
    };

    socket.on("b2b:order:created", refreshOrders);
    socket.on("b2b:order:updated", refreshOrders);
    return () => {
      socket.off("b2b:order:created", refreshOrders);
      socket.off("b2b:order:updated", refreshOrders);
    };
  }, [dispatch, filterStatus, filterType, searchText]);

  const { orders, isLoading } = useSelector((state) => state.b2b);

  const columns = [
    {
      title: "Order ID",
      dataIndex: "txRef",
      render: (text, record) => (
        <div className="flex flex-col">
          <Link
            to={`/admin/b2b/orders/${record.id}`}
            className="font-mono text-[11px] font-black text-blue-600 bg-blue-50 px-2.5 py-1 rounded-lg border border-blue-100 uppercase w-fit"
          >
            #{record.id.slice(-6)}
          </Link>
          {record.purchaseOrderNumber && (
            <span className="text-[10px] text-slate-400 font-bold mt-1 uppercase tracking-widest">
              PO: {record.purchaseOrderNumber}
            </span>
          )}
        </div>
      ),
    },
    {
      title: "Client / Institution",
      dataIndex: "user",
      render: (user, record) => (
        <div className="flex flex-col">
          <span className="font-bold text-slate-800 text-[15px] leading-tight">
            {user?.institutionName || "Individual Buyer"}
          </span>
          <span className="text-[12px] text-slate-400 font-medium mt-0.5">
            {record.firstName} {record.lastName}
          </span>
        </div>
      ),
    },
    {
      title: "Amount",
      dataIndex: "totalPrice",
      render: (val) => (
        <span className="font-black text-slate-900">
          {parseFloat(val).toLocaleString()}{" "}
          <span className="text-[10px] text-slate-400">ETB</span>
        </span>
      ),
    },
    {
      title: "Payment",
      dataIndex: "creditPurchase",
      render: (isCredit) => (
        <div className="flex items-center gap-1.5">
          <CreditCard size={14} className={isCredit ? "text-indigo-500" : "text-emerald-500"} />
          <span className={`text-[12px] font-bold ${isCredit ? "text-indigo-600" : "text-emerald-600"}`}>
            {isCredit ? "CREDIT" : "PREPAID"}
          </span>
        </div>
      ),
    },
    {
      title: "Procurement Status",
      dataIndex: "procurementStatus",
      render: (status) => (
        <div
          className={`status-badge ${
            status === "DELIVERED"
              ? "success"
              : status === "CANCELLED"
              ? "danger"
              : status === "APPROVED" || status === "PROCESSING"
              ? "active"
              : "info"
          }`}
        >
          <div
            className={`w-1.5 h-1.5 rounded-full ${
              status === "DELIVERED"
                ? "bg-emerald-500"
                : status === "CANCELLED"
                ? "bg-rose-500"
                : status === "APPROVED" || status === "PROCESSING"
                ? "bg-blue-500"
                : "bg-slate-400"
            }`}
          />
          {status || "PENDING"}
        </div>
      ),
    },
    {
      title: "Placed At",
      dataIndex: "createdAt",
      render: (date) => (
        <span className="text-slate-500 font-bold text-xs">
          {new Date(date).toLocaleDateString()}
        </span>
      ),
    },
    {
      title: "Actions",
      dataIndex: "id",
      render: (id) => (
        <div className="flex items-center gap-2">
          <Tooltip title="Manage Order Fulfillment">
            <Link to={`/admin/b2b/orders/${id}`}>
              <Button
                type="text"
                icon={<Eye size={18} />}
                className="text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-xl w-10 h-10 flex items-center justify-center border border-transparent hover:border-slate-100"
              />
            </Link>
          </Tooltip>
        </div>
      ),
    },
  ];

  const dataSource = orders || [];

  return (
    <div className="space-y-8 pb-12">
      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-[28px] font-bold text-slate-900 tracking-tight">
            Wholesale Orders
          </h1>
          <p className="text-[15px] text-slate-500 mt-1 font-medium">
            Approve credit billing, track batch assignments, and dispatch shipments.
          </p>
        </div>
        <div className="relative w-full sm:w-80">
          <Search
            className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400"
            size={18}
          />
          <input
            type="text"
            placeholder="Search order ID or institution..."
            className="pl-10 pr-4 h-11 w-full bg-white border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500/20 text-[14px] font-medium"
            onChange={(e) => setSearchText(e.target.value)}
          />
        </div>
      </div>

      <div className="bg-white rounded-2xl border border-slate-100 overflow-hidden shadow-sm">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center p-6 border-b border-slate-50 gap-4">
          <div className="flex items-center gap-4">
            <div className="p-3 bg-blue-50 rounded-xl text-blue-600">
              <ShoppingBag size={20} />
            </div>
            <div>
              <span className="text-[15px] font-bold text-black border-slate-100 pr-4 mr-4 border-r">
                Orders Registry
              </span>
              <span className="text-[14px] text-slate-500 font-medium">
                Active Wholesale Orders:{" "}
                <span className="text-black font-bold">{dataSource.length}</span>
              </span>
            </div>
          </div>
          <div className="flex flex-wrap items-center gap-4">
            <div className="flex items-center gap-2">
              <span className="text-[13px] font-bold text-slate-400 uppercase tracking-widest">
                Procurement:
              </span>
              <Select
                defaultValue="all"
                onChange={(val) => setFilterStatus(val)}
                className="w-44 modern-select"
                bordered={false}
              >
                <Select.Option value="all">All Statuses</Select.Option>
                <Select.Option value="PENDING_APPROVAL">Pending Approval</Select.Option>
                <Select.Option value="APPROVED">Approved</Select.Option>
                <Select.Option value="PROCESSING">Processing</Select.Option>
                <Select.Option value="SHIPPED">Shipped</Select.Option>
                <Select.Option value="DELIVERED">Delivered</Select.Option>
                <Select.Option value="CANCELLED">Cancelled</Select.Option>
              </Select>
            </div>

            <div className="flex items-center gap-2">
              <span className="text-[13px] font-bold text-slate-400 uppercase tracking-widest">
                Bill Type:
              </span>
              <Select
                defaultValue="all"
                onChange={(val) => setFilterType(val)}
                className="w-44 modern-select"
                bordered={false}
              >
                <Select.Option value="all">All Orders</Select.Option>
                <Select.Option value="CREDIT">Credit Only</Select.Option>
                <Select.Option value="BULK">Cash / Prepaid</Select.Option>
              </Select>
            </div>
          </div>
        </div>

        <Table
          columns={columns}
          dataSource={dataSource}
          loading={isLoading}
          pagination={{
            pageSize: 10,
            className: "px-6 py-4",
          }}
          className="modern-table"
          rowKey="id"
        />
      </div>
    </div>
  );
};

export default B2bOrderList;
